BEGIN;CREATE TABLE IF NOT EXISTS calendar_oauth_states (  state TEXT PRIMARY KEY,  user_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,  organization_id TEXT NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,  expires_at TIMESTAMPTZ NOT NULL,  consumed_at TIMESTAMPTZ,  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());CREATE INDEX IF NOT EXISTS idx_calendar_oauth_states_expiry  ON calendar_oauth_states (expires_at, consumed_at);COMMIT;